%[text] #### Experiment 1
load("lab3_exp1_data.mat")

% Plot with currents as a function of base voltage
figure() %[output:4ef028c7]
yscale("log") %[output:4ef028c7]
hold on; %[output:4ef028c7]
semilogy(Vb, Ib, '.', DisplayName='Measured Base Current') %[output:4ef028c7]
yscale("log") %[output:4ef028c7]
semilogy(Vb, Iout, '.', DisplayName='Measured Collector Current') %[output:4ef028c7]
xlabel('Base Voltage (V)') %[output:4ef028c7]
ylabel('Current (A)') %[output:4ef028c7]
title('Bipolar Transistor Current Characteristics') %[output:4ef028c7]

% Theoretical Fit Values
I_s = 3e-15; % Typical Value (A)
U_T = 25e-3; % Typical Value (V)
beta = 175; % See flat region in BJT Current Gain Chars. plot (Unitless)

semilogy(Vb, (I_s ./ beta) .* exp(Vb ./ U_T), DisplayName='Theoretical Fit: I_b = (I_s/\beta) e^{V_{be}/U_T}; \beta: 175, U_T: 25 mV, I_s: 3 fA') %[output:4ef028c7]
semilogy(Vb, I_s .* exp(Vb ./ U_T), DisplayName='Theoretical Fit: I_c = I_s e^{V_{be}/U_T}; U_T: 25 mV, I_s: 3 fA') %[output:4ef028c7]

legend(Location='southoutside') %[output:4ef028c7]

% Current Gain Plot
current_gain = Iout ./ Ib;

figure() %[output:5d6669d5]
semilogx(Ib, current_gain, '.', DisplayName='Measured') %[output:5d6669d5]
hold on; %[output:5d6669d5]
vals_range = find(Ib > 1e-10);
plot_range = logspace(-10, -5, 101);
% fit_vals = fit(log(Ib(vals_range))', log(current_gain(vals_range))', "exp(a * x + b)");
% plot(plot_range, exp(fit_vals(1) .* plot_range + fit_vals(2)), DisplayName='Theoretical Fit')

xlabel('Base Current (A)') %[output:5d6669d5]
ylabel('Current Gain, \beta (Unitless)') %[output:5d6669d5]
title('Bipolar Transistor Current Gain Characteristics') %[output:5d6669d5]
% legend(Location='southoutside')
axis([1e-10, 1e-4, 0, 300]) %[output:12c3a063] %[output:5d6669d5]

% r_b vs I_b
incremental_resistance = diff(Vb) ./ diff(Ib);

figure() %[output:056b3873]
loglog(Ib(1:end-1), incremental_resistance, '.', DisplayName='Measured') %[output:056b3873]
hold on; %[output:056b3873]
plot(logspace(-10, -5, 101), 0.025 ./ logspace(-10, -5, 101), DisplayName='Theoretical Fit') %[output:056b3873]

xlabel('Base Current (A)') %[output:056b3873]
ylabel('Incremental Resistance, r_{b} (\Omega)') %[output:056b3873]
title('Bipolar Transistor Incremental Resistance Characteristics') %[output:056b3873]
legend(Location='southoutside') %[output:056b3873]

% g_m vs I_c
incremental_transconductance_gain = diff(Iout) ./ diff(Vb);

figure() %[output:474e85c0]
loglog(Iout(1:end-1), incremental_transconductance_gain, '.', DisplayName='Measured') %[output:474e85c0]
hold on; %[output:474e85c0]
plot(logspace(-10, -2, 101), logspace(-10, -2, 101) ./ 0.025, DisplayName='Theoretical Fit') %[output:474e85c0]

xlabel('Collector Current (A)') %[output:474e85c0]
ylabel(['Incremental Transconductance Gain, g_{m} (', char(8487), ')']) %[output:474e85c0]
title('Bipolar Transistor Incremental Transconductance Characteristics') %[output:474e85c0]
legend(Location='southoutside') %[output:474e85c0]
%[text] #### Experiment 4
load("lab3_exp3_data.mat")
load("lab3_exp4_data.mat")

% Voltage Transfer Characteristic Plot + Experiment 3 Plot
figure() %[output:455f8207]
hold on; %[output:455f8207]
plot(Vin10k_e4, Vout10k_e4, '.', DisplayName='mR = 10 k\Omega; R = 1 k\Omega') %[output:455f8207]
plot(Vin5k_e4, Vout5k_e4, '.', DisplayName='mR = 5 k\Omega; R = 1 k\Omega') %[output:455f8207]
plot(Vin2k_e4, Vout2k_e4, '.', DisplayName='mR = 2 k\Omega; R = 1 k\Omega') %[output:455f8207]
plot(Vin_e3, Vout_e3, '.', DisplayName='mR = 0 \Omega; R = 1 k\Omega (Common Collector Amplifier)') %[output:455f8207]

fit_vals = polyfit(Vin_e3(find(Vout_e3 > 0.75)), Vout_e3(find(Vout_e3 > 0.75)), 1);
plot(linspace(0, 5, 101), fit_vals(1) .* linspace(0, 5, 101) + fit_vals(2), DisplayName=['Common Collector Amplifier Behavior Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:455f8207]

vals_range = find(Vin10k_e4 > 0.5 & Vin10k_e4 < 1.15);
plot_range = linspace(0.5, 1.25, 101);
fit_vals = polyfit(Vin10k_e4(vals_range), Vout10k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 10 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:455f8207]

vals_range = find(Vin5k_e4 > 0.5 & Vin5k_e4 < 1.5);
plot_range = linspace(0.5, 1.75, 101);
fit_vals = polyfit(Vin5k_e4(vals_range), Vout5k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 5 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:455f8207]

vals_range = find(Vin2k_e4 > 0.5 & Vin2k_e4 < 2.2);
plot_range = linspace(0.5, 3, 101);
fit_vals = polyfit(Vin2k_e4(vals_range), Vout2k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 2 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:455f8207]

title('Common-Emitter Amplifier Voltage Transfer Characteristics') %[output:455f8207]
xlabel('Input Voltage (V)') %[output:455f8207]
ylabel('Output Voltage (V)') %[output:455f8207]
legend(Location="southoutside") %[output:455f8207] %[output:6b2bab80] %[output:169e9174] %[output:205e7ed0] %[output:29889ba4] %[output:27a296ea] %[output:320bae85]

